const d = $json.body;

// Compute SOL date (accident + 8 years)
const accDate = new Date(d.date_of_accident);
const solDate = new Date(accDate);
solDate.setFullYear(solDate.getFullYear() + 8);
const sol_date = solDate.toISOString().split('T')[0];

// Compute pronouns
const sex = (d.client_sex || 'M').trim().toUpperCase();
const pronoun_possessive = sex === 'F' ? 'her' : 'his';
const pronoun_subject = sex === 'F' ? 'she' : 'he';
const pronoun_object = sex === 'F' ? 'her' : 'him';

return {
  client_name: d.client_name,
  date_of_accident: d.date_of_accident,
  defendant_name: d.defendant_name,
  accident_location: d.accident_location,
  client_vehicle_plate: d.client_vehicle_plate,
  number_of_injured: Number(d.number_of_injured) || 0,
  accident_description: d.accident_description,
  client_sex: d.client_sex,
  confidence_score: Number(d.confidence_score) || 0,
  sol_date: sol_date,
  matter_id: d.matter_id,
  case_id: d.case_id,
  pronoun_possessive: pronoun_possessive,
  pronoun_subject: pronoun_subject,
  pronoun_object: pronoun_object,
  verified: true,
  verified_at: d.verified_at,
  CLIO_API_BASE: 'https://app.clio.com/api/v4',
  WORKFLOW_B_ID: '3NUwqSxkpFg7RhBP'
};
